async function sendRawTransaction(data, to = null) {
    const account = await cfx.getAccount(fromAddress);
    console.log(`balance of fromAddress------${account.balance}`);
    // raw
    const nonce = await cfx.getNextNonce(fromAddress);
    console.log(`nonce------${JSON.stringify(nonce)}`);
    const estimate = {gasLimit: 5000000, storageCollateralized: 1024}; // await cfx.estimateGasAndCollateral({ from: fromAddress, to: null, nonce, data }); not implemented in consortium
    console.log(`estimateGas------${JSON.stringify(estimate)}`);
    const epochNumber = await cfx.getEpochNumber();
    console.log(`proposedEpoch------${JSON.stringify(epochNumber)}`);
    const gasPrice = BigInt(10000000000); // await cfx.getGasPrice(); not implemented in consortium
    console.log(`estimateGasPrice------${JSON.stringify(gasPrice)}`);
    const rawTransaction = {
        nonce,
        gasPrice,
        gas: estimate.gasLimit,
        to,
        value : 0,
        storageLimit: estimate.storageCollateralized, // unused in consortium
        epochHeight: epochNumber,
        chainId: 0,
        data,
    };
    const tx = new ConsortiumTransaction(rawTransaction);
    console.log(`------tx:\n${JSON.stringify(tx)}}\n------`)

    // sign
    tx.sign(fromAddressPrivateKey, networkId);
    console.log(`------txSigned:\n${JSON.stringify(tx)}\n------`)

    // hex
    const serializedTx = tx.serialize();
    console.log(`------txSerialized:\n${JSON.stringify(serializedTx)}\n------`)

    // call or send
    let receipt
    if(debug) {
        // call
        receipt = await cfx.call({ from: fromAddress, to, gasPrice, gas: estimate.gasLimit, value : 0, data, nonce });
    } else{
        // send
        receipt = await cfx.sendRawTransaction(serializedTx).executed();
    }

    console.log(`------receipt:\n${JSON.stringify(receipt)}\n------`)
    return receipt;
}

// ------------------- deploy contracts used by scan ---------------------
async function deployAnnouncement() {
    const data = '';
    const {transactionHash: txHash, contractCreated} = await sendRawTransaction(data);
    console.log(`contract announcement ${contractCreated} deployed at tx ${txHash} `);

}

async function deployScanUtil() {
    const data = '';
    const {transactionHash: txHash, contractCreated} = await sendRawTransaction(data);
    console.log(`contract scan-util ${contractCreated} deployed at tx ${txHash} `);
}

async function deploy1820() {
    const create2Factory = 'CFX:TYPE.CONTRACT:ACABC58X6FTJM7432VHT9YJAPERG75APPJ7D7VN573';// await deployCreate2Factory();
    if(!create2Factory) {
        console.log(`create2Factory not deployed!`);
        return;
    }

    const {codeHash} = await cfx.getAccount('0x88887eD889e776bCBe2f0f9932EcFaBcDfCd1820')
    if (codeHash !== ethers.utils.keccak256(Buffer.from(""))) {
        console.log(`skip create contract 1820 because it exists already!`);
        return;
    }

    const data = '';
    const {transactionHash: txHash, contractCreated} = await sendRawTransaction(data, create2Factory);
    console.log(`contract 1820 ${contractCreated} deployed at tx ${txHash} `);
}

async function deployCreate2Factory() {
    const data = '';
    const {transactionHash: txHash, contractCreated} = await sendRawTransaction(data);
    console.log(`contract Create2Factory ${contractCreated} deployed at tx ${txHash} `);
    return contractCreated;
}

async function deploy() {
    /*await deployAnnouncement();
    await deployScanUtil();*/
    await deploy1820();
}

// ------------------------ entry point method ---------------------------
async function init() {
    cfx = await initCfxSdk({
        url,
        networkId,
        defaultGasPrice: 1_000_000_000,
        logger: console,
    });

    if(type === 10) {
        const account = cfx.wallet.addPrivateKey(fromAddressPrivateKey);
        fromAddress = format.hexAddress(account.toString());
        const fromAddressBalance = await cfx.getBalance(account.toString());
        console.log(`account ${account} with hex ${format.hexAddress(account.toString())} has balance ${formatEther(fromAddressBalance)}`);
    }
}

async function run() {
    await init();
    if(type === 0) {
        await call();
    }
    if(type === 1) {
        await getStatus();
    }
    if(type === 2) {
        await getAccount(addr);
    }
    if(type === 3) {
        await getNextNonce(addr);
    }
    if(type === 4) {
        await getTransactionByHash(txHash);
    }
    if(type === 5) {
        await getTransactionReceipt(txHash);
    }

    if(type === 10) {
        await deploy();
    }
}

async function main() { // node common/contract/deploy.js url networkId pk
    const args = process.argv.slice(2);
    url = args[0];
    networkId = Number(args[1]);
    type = Number(args[2]);
    console.log(`url ${url} networkId ${networkId} type ${type}`)

    if(type === 2 || type === 3) {
        addr = args[3];
        console.log(`type ${type} addr ${addr}`)
    }
    if(type === 4 || type === 5) {
        txHash = args[3];
        console.log(`type ${type} txHash ${txHash}`)
    }
    if(type === 10) {
        fromAddressPrivateKey = args[3];
        (args?.length === 5) && (debug = args[4]);
        console.log(`type ${type} debug ${debug}`)
    }

    run().then();
}

main().then();
